46	char compare_single_items(int item_idx1, int item_idx2) {
47	    if (item_idx1 == item_idx2) return '=';
48	
49	    std::pair<int, int> query_pair_key = {std::min(item_idx1, item_idx2), std::max(item_idx1, item_idx2)};
50	
51	    auto it = comparison_results_cache_1v1.find(query_pair_key);
52	    if (it != comparison_results_cache_1v1.end()) {
53	        char cached_res = it->second;
54	        if (item_idx1 == query_pair_key.first) return cached_res;
55	        return (cached_res == '<' ? '>' : (cached_res == '>' ? '<' : '='));
56	    }
57	
58	    if (queries_made >= Q_total_global) {
59	        return '='; 
60	    }
61	
62	    char res_direct = perform_query_actual({item_idx1}, {item_idx2});
63	
64	    if (item_idx1 < item_idx2) {
65	        comparison_results_cache_1v1[query_pair_key] = res_direct;
66	    } else { 
67	        char reversed_res = (res_direct == '<' ? '>' : (res_direct == '>' ? '<' : '='));
68	        comparison_results_cache_1v1[query_pair_key] = reversed_res;
69	    }
70	    return res_direct;
71	}
