98	void merge_for_sort(std::vector<int>& items_to_sort, int left, int mid, int right) {
99	    int n1 = mid - left + 1;
100	    int n2 = right - mid;
101	    std::vector<int> L_half(n1), R_half(n2);
102	    for (int i = 0; i < n1; i++) L_half[i] = items_to_sort[left + i];
103	    for (int j = 0; j < n2; j++) R_half[j] = items_to_sort[mid + 1 + j];
104	
105	    int i = 0, j = 0, k = left;
106	    while (i < n1 && j < n2) {
107	        char cmp_res = compare_single_items(L_half[i], R_half[j]);
108	        if (cmp_res == '<' || cmp_res == '=') {
109	            items_to_sort[k++] = L_half[i++];
110	        } else { 
111	            items_to_sort[k++] = R_half[j++];
112	        }
113	    }
114	    while (i < n1) items_to_sort[k++] = L_half[i++];
115	    while (j < n2) items_to_sort[k++] = R_half[j++];
116	}
