# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    auto program_start_time = std::chrono::steady_clock::now();
    uint64_t random_seed = std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count();
    std::mt19937 rng(random_seed);

    int N, D, Q;
    std::cin >> N >> D >> Q;

    // Phase 1: Query phase - random balanced splits
    // Each query splits all N items into two halves randomly
    // This gives sign(sum_L - sum_R) information - a linear measurement of weights

    struct QueryData {
        std::vector<int> L_items;
        std::vector<int> R_items;
        char result;
    };

    std::vector<QueryData> all_queries;
    all_queries.reserve(Q);

    std::vector<int> perm(N);
    std::iota(perm.begin(), perm.end(), 0);

    for (int q = 0; q < Q; q++) {
        std::shuffle(perm.begin(), perm.end(), rng);
        int half = N / 2;

        QueryData qd;
        qd.L_items.assign(perm.begin(), perm.begin() + half);
        qd.R_items.assign(perm.begin() + half, perm.end());

        std::cout << qd.L_items.size() << " " << qd.R_items.size();
        for (int x : qd.L_items) std::cout << " " << x;
        for (int x : qd.R_items) std::cout << " " << x;
        std::cout << "\n";
        std::cout.flush();

        std::cin >> qd.result;
        all_queries.push_back(std::move(qd));
    }

    // Phase 2: Weight estimation using multiplicative SGD
    // Each comparison is a sign constraint on the linear combination of weights
    // We iteratively update weights to satisfy these constraints

    std::vector<double> w(N, 1.0);

    // Precompute side assignments: +1 for L, -1 for R
    // Use compact storage: for each query, store item->side mapping
    std::vector<std::vector<int8_t>> sides(Q, std::vector<int8_t>(N, 0));
    for (int q = 0; q < Q; q++) {
        for (int i : all_queries[q].L_items) sides[q][i] = 1;
        for (int i : all_queries[q].R_items) sides[q][i] = -1;
    }

    double eta = 0.08;
    int max_epochs = 5000;

    for (int epoch = 0; epoch < max_epochs; epoch++) {
        if (epoch % 50 == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time).count() > 900)
                break;
        }

        int violations = 0;
        double factor_up = 1.0 + eta;
        double factor_down = 1.0 / factor_up;

        for (int q = 0; q < Q; q++) {
            double sum_L = 0, sum_R = 0;
            for (int i : all_queries[q].L_items) sum_L += w[i];
            for (int i : all_queries[q].R_items) sum_R += w[i];

            char result = all_queries[q].result;

            if (result == '>' && sum_L <= sum_R) {
                for (int i : all_queries[q].L_items) w[i] *= factor_up;
