#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>

int N, D, Q;
int queries_used = 0;

char do_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_used++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << "\n";
    std::cout.flush();
    char c;
    std::cin >> c;
    return c;
}

char compare_groups(const std::vector<int>& grpA, const std::vector<int>& grpB) {
    if (grpA.empty() || grpB.empty()) return '=';
    return do_query(grpA, grpB);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    auto start_time = std::chrono::steady_clock::now();
    std::mt19937 rng(std::chrono::steady_clock::now().time_since_epoch().count());

    std::cin >> N >> D >> Q;

    // Strategy: Use queries for sorting items, then do greedy assignment with
    // direct group-sum comparisons, then refine partition with remaining queries.

    // Phase 1: Sort items using merge sort to get weight ordering
    // Budget: allocate about 60% of Q for sorting, rest for assignment + refinement

    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);

    // Merge sort with query budget awareness
    int sort_budget = Q * 6 / 10;

    // Merge sort implementation
    std::vector<int> temp_buf(N);
    bool budget_exceeded = false;

    // Bottom-up merge sort (easier to control budget)
    for (int width = 1; width < N && !budget_exceeded; width *= 2) {
        for (int i = 0; i < N && !budget_exceeded; i += 2 * width) {
            int left = i;
            int mid = std::min(i + width, N);
            int right = std::min(i + 2 * width, N);

            int p = left, q = mid, r = left;
            while (p < mid && q < right) {
                if (queries_used >= sort_budget) {
                    budget_exceeded = true;
                    // Copy remaining
                    while (p < mid) temp_buf[r++] = sorted_items[p++];
                    while (q < right) temp_buf[r++] = sorted_items[q++];
                    break;
                }
                char cmp = do_query({sorted_items[p]}, {sorted_items[q]});
                if (cmp == '<' || cmp == '=') {
                    temp_buf[r++] = sorted_items[p++];
                } else {
                    temp_buf[r++] = sorted_items[q++];
                }
            }
            while (p < mid) temp_buf[r++] = sorted_items[p++];
            while (q < right) temp_buf[r++] = sorted_items[q++];
        }
        for (int i = 0; i < N; i++) sorted_items[i] = temp_buf[i];
    }

    // Now sorted_items is sorted by weight (ascending, possibly partially if budget ran out)
